const newPassword = "NewPass123!";
// Step 1 – Trigger forgot password request manually via API
cy.request({
  method: "POST",
  url: `${Cypress.config("baseUrl")}/api/forgotPassword/${_Constants.default.resetPasswordEmail}`,
  failOnStatusCode: false
}).then(response => {
  expect(response.status).to.eq(200);
  expect(response.body.msg).to.eq("Email sent successfully");
  expect(response.body.resetToken).to.exist;
  const token = response.body.resetToken;
  // Step 2 – Build reset password link
  const resetUrl = `${Cypress.config("baseUrl")}/resetpassword/${token}`;
  cy.log("Reset URL:", resetUrl);
  // Step 3 – Visit reset password page
  cy.visit(resetUrl);
  // Simulate Offline Mode
  cy.simulateOffline();
  _LidarViewer.default.NewPasswordField.type(newPassword);
  _LidarViewer.default.ConfirmPasswordField.type(newPassword);
  _LidarViewer.default.ResetPasswordBtn.click();
  // Verify the toast text
  cy.get(".info-message-container .width-100", {
    timeout: 5000
  }).should("be.visible").and("contain.text", "Network error. Please check your internet connection and try again.");
  // Simulate Online Mode
  cy.simulateOnline();
});

